                                    >
                                        <Download className="w-3.5 h-3.5" /> Download Signed Copy
                                    </a>
                                )}
                                <button onClick={closeMedia} className="px-6 py-2 bg-emerald-500 text-white font-bold rounded-xl text-xs uppercase tracking-widest">
                                    Done
                                </button>
                            </div>
