                                    {isPolicyDoc && (
                                        <div className="p-6 bg-[#0d9488]/5 rounded-3xl border border-[#0d9488]/10 space-y-4">
                                            <p className="text-sm text-slate-700 dark:text-slate-300 leading-relaxed font-medium">
