```typescript
// Clean up raw filenames for display
const cleanFileName = (name: string): string => {
    return name
        .replace(/\.[^.]+$/, '')           // Remove extension
        .replace(/_\d{13,}$/g, '')         // Remove trailing timestamps
        .replace(/^\d+_/, '')              // Remove leading timestamps
        .replace(/_/g, ' ')               // Underscores to spaces
        .replace(/\b\w/g, l => l.toUpperCase()); // Title Case
};

// Relative date: "Just now", "2h ago", "Yesterday", "16 Feb"
const formatRelativeDate = (dateStr: string): string => {
    const date = new Date(dateStr);
    const now = new Date();
    const diffMs = now.getTime() - date.getTime();
    const diffMins = Math.floor(diffMs / 60000);
    const diffHours = Math.floor(diffMs / 3600000);
    const diffDays = Math.floor(diffMs / 86400000);

    if (diffMins < 2) return 'Just now';
    if (diffMins < 60) return `${diffMins}m ago`;
    if (diffHours < 24) return `${diffHours}h ago`;
    if (diffDays === 1) return 'Yesterday';
    return date.toLocaleDateString('en-ZA', { day: 'numeric', month: 'short' });
};

// Status badge component
const StatusBadge: React.FC<{ status: string }> = ({ status }) => {
    const config: Record<string, { bg: string; text: string; label: string }> = {
        countersigned: { bg: 'bg-emerald-100', text: 'text-emerald-700', label: 'Countersigned' },
        signed: { bg: 'bg-teal-100', text: 'text-teal-700', label: 'Signed' },
        verified: { bg: 'bg-blue-100', text: 'text-blue-700', label: 'Verified' },
        uploaded: { bg: 'bg-slate-100', text: 'text-slate-500', label: 'Uploaded' },
    };
    const c = config[status?.toLowerCase()] || config.uploaded;
    return (
        <span className={`px-1.5 py-0.5 rounded text-[7px] font-bold uppercase tracking-wider ${c.bg} ${c.text}`}>
            {c.label}
        </span>
    );
};

// Type-to-icon mapping
const typeIcons: Record<string, JSX.Element> = {
