const StaffDashboard: React.FC = () => {
    const { setIsCopilotOpen, triggerHubRefresh, hubRefreshKey, homeActiveTab, setHomeActiveTab, setFocusedHireId, setCurrentHire, setCurrentHireId, openMedia } = useAppContext();
    const [pipeline, setPipeline] = useState<any[]>([]);
    const [loading, setLoading] = useState(true);
    const [overviewFilter, setOverviewFilter] = useState<'all' | 'stalled' | 'in-progress' | 'completed'>('all');

    const fetchData = async () => {
        setLoading(true);
        try {
            const resp = await fetch(
                `${SUPABASE_URL}/rest/v1/onboarding_telemetry?select=id,staff_name,status,step_reached,updated_at,created_at,metadata`,
                { headers: { 'apikey': SUPABASE_KEY, 'Authorization': `Bearer ${SUPABASE_KEY}` } }
            );
            const hires = await resp.json();
            setPipeline(hires || []);
        } catch (e) {
            console.error("Dashboard refresh failure", e);
        } finally {
            setLoading(false);
        }
    };

    useEffect(() => {
        fetchData();
    }, [hubRefreshKey]);

    const metrics = useMemo(() => {
        const now = new Date();
        const active = pipeline.filter(h => h.status?.toLowerCase() === 'in_progress' || !h.status || h.status?.toLowerCase() === 'pending').length;
        const completedCount = pipeline.filter(h => h.status?.toLowerCase() === 'completed' || h.step_reached >= 7).length;
        const stalled = pipeline.filter(h => {
            if (h.status?.toLowerCase() === 'completed' || h.step_reached >= 7) return false;
            const updated = new Date(h.updated_at || h.created_at);
            const diffHours = (now.getTime() - updated.getTime()) / (1000 * 60 * 60);
            return diffHours > 24;
        }).length;
        const processRate = pipeline.length > 0 ? Math.round((completedCount / pipeline.length) * 100) : 0;
        const registryCompleteness = pipeline.length > 0 
            ? Math.round((pipeline.filter(h => (h.step_reached || 1) >= 4).length / pipeline.length) * 100)
            : 0;

        return { active, stalled, completedCount, processRate, registryCompleteness };
    }, [pipeline]);

    const filteredRecentActivity = useMemo(() => {
        const now = new Date();
        let list = pipeline.map(hire => ({
            name: hire.staff_name || 'Unknown',
