    const generateSignatureCertificate = async (name: string, title: string, hash: string): Promise<Blob> => {
        const doc = new jsPDF();
        doc.setFillColor(15, 23, 42);
        doc.rect(0, 0, 210, 40, 'F');

        doc.setTextColor(255, 255, 255);
        doc.setFontSize(22);
        doc.setFont('helvetica', 'bold');
        doc.text("DIGITAL SIGNATURE CERTIFICATE", 20, 25);

        doc.setTextColor(100, 116, 139);
        doc.setFontSize(10);
        doc.text(`AIVA Digital Signing v1.0 | Document: ${fileName}`, 20, 35);

        doc.setTextColor(15, 23, 42);
        doc.setFontSize(14);
        doc.text("SIGNING SUMMARY", 20, 60);

        doc.setFontSize(11);
        doc.setFont('helvetica', 'normal');
        const summary = `This certificate confirms the digital signing of the contract: ${fileName}. Identity verified through AIVA Digital Signing.`;
        doc.text(doc.splitTextToSize(summary, 170), 20, 70);

        doc.setFillColor(248, 250, 252);
        doc.roundedRect(20, 100, 170, 80, 5, 5, 'F');

        doc.setFont('helvetica', 'bold');
        doc.text("SIGNATORY DETAILS", 30, 115);
        doc.setFont('helvetica', 'normal');
        doc.text(`Legal Name: ${name}`, 30, 125);
        doc.text(`Designation: ${title}`, 30, 135);
        doc.text(`Company: Nashua Paarl & West Coast`, 30, 145);
        doc.text(`Timestamp: ${new Date().toLocaleString('en-ZA')}`, 30, 155);
        doc.text(`Reference: ${hash}`, 30, 165);

        doc.setFontSize(30);
        doc.setFont('courier', 'italic');
        doc.setTextColor(30, 58, 138);
        doc.text(name, 30, 220);

        doc.setDrawColor(30, 58, 138);
        doc.line(30, 225, 120, 225);
        doc.setFontSize(8);
        doc.setTextColor(100, 116, 139);
        doc.text("OFFICIAL DIGITAL SIGNATURE", 30, 230);

        doc.setFontSize(7);
        doc.text("AIVA Digital Signing • Nashua Paarl", 105, 285, { align: 'center' });

        return doc.output('blob');
    };

    const embedSignatureOnPdf = async (
        sourcePdfUrl: string,
        signerName: string,
        signerRole: string, // 'Employee' or 'Managing Director'
        docHash: string
    ): Promise<Blob> => {
        // Fetch the source PDF (template for employee, signed copy for manager)
        const existingPdfBytes = await fetch(sourcePdfUrl).then(res => res.arrayBuffer());
        const pdfDoc = await PDFDocument.load(existingPdfBytes);

        const pages = pdfDoc.getPages();
        const lastPage = pages[pages.length - 1];
        const { width, height } = lastPage.getSize();

        const helvetica = await pdfDoc.embedFont(StandardFonts.Helvetica);
        const helveticaBold = await pdfDoc.embedFont(StandardFonts.HelveticaBold);
        const courier = await pdfDoc.embedFont(StandardFonts.Courier);

        const timestamp = new Date().toLocaleString('en-ZA', { timeZone: 'Africa/Johannesburg' });
        const isCountersign = signerRole === 'Managing Director';

        // ─── SIGNATURE BLOCK POSITION ───
        const sigX = isCountersign ? width / 2 + 40 : 50;
        const sigBaseY = 120; // Distance from bottom of page

        // ─── SIGNATURE LINE ───
        lastPage.drawLine({
            start: { x: sigX, y: sigBaseY + 50 },
            end: { x: sigX + 200, y: sigBaseY + 50 },
            thickness: 1,
            color: rgb(0.2, 0.2, 0.2),
        });

        // ─── TYPED SIGNATURE (large, ink-blue) ───
        lastPage.drawText(signerName, {
            x: sigX + 10,
            y: sigBaseY + 60,
            size: 22,
            font: helveticaBold,
            color: rgb(0.05, 0.15, 0.45),
        });

        // ─── ROLE LABEL ───
        lastPage.drawText(signerRole, {
            x: sigX,
            y: sigBaseY + 35,
            size: 8,
            font: helvetica,
            color: rgb(0.4, 0.4, 0.4),
        });

        // ─── DATE ───
        lastPage.drawText(`Date: ${timestamp}`, {
            x: sigX,
            y: sigBaseY + 22,
            size: 7,
            font: helvetica,
            color: rgb(0.4, 0.4, 0.4),
        });

        // ─── DOCUMENT HASH ───
        lastPage.drawText(`Ref: ${docHash}`, {
            x: sigX,
            y: sigBaseY + 10,
            size: 6,
            font: courier,
            color: rgb(0.5, 0.5, 0.5),
        });

        // ─── "DIGITALLY SIGNED" BADGE ───
        const badgeX = sigX;
        const badgeY = sigBaseY - 5;

        lastPage.drawRectangle({
            x: badgeX,
            y: badgeY,
            width: 110,
            height: 14,
            color: rgb(0.05, 0.58, 0.53),
            borderColor: rgb(0.04, 0.49, 0.45),
            borderWidth: 0.5,
        });

        lastPage.drawText('DIGITALLY SIGNED - AIVA', {
            x: badgeX + 5,
            y: badgeY + 3,
            size: 7,
            font: helveticaBold,
            color: rgb(1, 1, 1),
        });

        // ─── COMPANY FOOTER (only on employee sign) ───
        if (!isCountersign) {
            lastPage.drawText('Nashua Paarl & West Coast - AIVA Digital Signing', {
                x: width / 2 - 100,
                y: 25,
                size: 6,
                font: helvetica,
                color: rgb(0.6, 0.6, 0.6),
            });
        }

        // ─── "FULLY EXECUTED" HEADER (only on countersign) ───
        if (isCountersign) {
            const firstPage = pages[0];
            firstPage.drawText('FULLY EXECUTED', {
                x: width / 2 - 80,
                y: height - 30,
                size: 12,
                font: helveticaBold,
                color: rgb(0.05, 0.58, 0.53),
