    const buttonColorClass = (isOfferDoc || isPolicyDoc)
        ? 'bg-[#0d9488] border-[#0a7c72] hover:brightness-110 shadow-[0_10px_30px_rgba(13,148,136,0.3)]'
        : isManagerPersona 
