interface LoginScreenProps {
    onLogin: () => void;
    onKioskMode: () => void;
    onDemoBypass: (role: 'employee' | 'manager') => void;
}

export const LoginScreen: React.FC<LoginScreenProps> = ({ onLogin, onKioskMode, onDemoBypass }) => {
