    const [country, setCountry] = useState<'ZA' | 'US'>('ZA');
    const [step, setStep] = useState<'credentials' | 'mfa' | 'verifying' | 'success'>('credentials');
    const [verificationStepIndex, setVerificationStepIndex] = useState(0);
    const [formattedPhone, setFormattedPhone] = useState('');

    // --- DEV MODE LOGIC ---
    const [logoTaps, setLogoTaps] = useState(0);
    const [isDev, setIsDev] = useState(
        new URLSearchParams(window.location.search).get('dev') === 'true' || 
        localStorage.getItem('aiva_dev') === 'true'
    );

    const handleLogoTap = () => {
        const newTaps = logoTaps + 1;
        setLogoTaps(newTaps);

        if (newTaps >= 3) {
            const newDev = !isDev;
            setIsDev(newDev);
            if (newDev) {
                localStorage.setItem('aiva_dev', 'true');
            } else {
                localStorage.removeItem('aiva_dev');
            }
            setLogoTaps(0);
        }

        // Reset tap counter after 2 seconds of no taps
        const timer = setTimeout(() => setLogoTaps(0), 2000);
        return () => clearTimeout(timer);
    };

    const verificationSteps = [
        { id: 1, label: "Secure Handshake", icon: <AivaAvatar /> },
        { id: 2, label: "FaceID Biometrics", icon: <FaceSmileIcon className="w-4 h-4 text-purple-500" /> },
        { id: 3, label: "Nashua Paarl Sync", icon: <MapPinIcon className="w-4 h-4 text-emerald-500" /> },
        { id: 4, label: "HR Registry Access", icon: <ShieldCheckIcon className="w-4 h-4 text-amber-500" /> },
        { id: 5, label: "WestFlow Compliance", icon: <LockClosedIcon className="w-4 h-4 text-blue-500" /> }
    ];

    const handleLoginClick = (e: React.FormEvent) => {
        e.preventDefault();
        let cleanPhone = phone.replace(/\D/g, '');
        if (cleanPhone.length === 10) {
            cleanPhone = (country === 'US' ? '+1' : '+27') + cleanPhone;
        } else if (!cleanPhone.startsWith('+')) {
            cleanPhone = '+' + cleanPhone;
        }
        setFormattedPhone(cleanPhone);
        setStep('mfa');
    };

    const handleMfaSuccess = () => {
        setStep('verifying');
    };

    useEffect(() => {
        if (step === 'verifying') {
            if (verificationStepIndex < verificationSteps.length) {
                const timer = setTimeout(() => setVerificationStepIndex(v => v + 1), 500);
                return () => clearTimeout(timer);
            } else {
                setTimeout(() => {
                    setStep('success');
                    setTimeout(onLogin, 800);
                }, 300);
            }
        }
    }, [step, verificationStepIndex, onLogin]);

    return (
        <div className="light h-full min-h-[100dvh] w-full bg-slate-50 flex flex-col items-center p-4 md:p-6 relative overflow-y-auto copilot-scrollbar font-sans">
            {/* Mesh Background Pattern */}
            <div className="fixed inset-0 opacity-[0.03] pointer-events-none" style={{ backgroundImage: 'radial-gradient(circle at 1px 1px, #1e3a8a 1px, transparent 0)', backgroundSize: '30px 30px' }}></div>

            {step === 'mfa' && (
                <IValtMfaModal 
                    phoneNumber={formattedPhone} 
                    onSuccess={handleMfaSuccess} 
                    onClose={() => setStep('credentials')} 
                />
            )}

            {/* Centering Wrapper */}
            <div className="w-full max-w-lg mx-auto z-10 relative animate-fadeIn flex flex-col items-center py-8 md:py-12 my-auto">
                <main className="bg-white/95 backdrop-blur-2xl w-full rounded-[2.5rem] shadow-[0_20px_80px_rgba(30,58,138,0.12)] border border-slate-200 overflow-hidden">
