                       <div className="flex items-center gap-3 w-full justify-center">
                           <div className="h-px w-8 bg-slate-200"></div>
                           <p className="text-slate-500 text-[10px] font-black uppercase tracking-[0.4em] whitespace-nowrap">Staff / Manager Access</p>
                           <div className="h-px w-8 bg-slate-200"></div>
