                    </div>

                    <div className="p-6 md:p-10 space-y-6 bg-slate-50/50 border-t border-slate-100">
                        {step === 'credentials' && (
                            <div className="space-y-8 animate-fadeIn">
                                <form onSubmit={handleLoginClick} className="space-y-6">
                                    <div className="space-y-4">
