                                            <Shield className="absolute left-4 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-300 group-focus-within:text-brand-primary transition-colors pointer-events-none" />
                                            <input 
                                                type="email" 
                                                value={username} 
                                                onChange={(e) => setUsername(e.target.value)} 
                                                className="w-full bg-white border-2 border-slate-100 text-slate-900 text-sm rounded-xl pl-11 pr-4 py-3.5 focus:border-brand-primary focus:bg-white outline-none transition-all font-bold shadow-inner" 
                                                placeholder="Corporate Email"
                                                required 
                                            />
                                        </div>

                                        <div className="grid grid-cols-3 gap-3">
                                            <select value={country} onChange={(e) => setCountry(e.target.value as any)} className="w-full bg-white border-2 border-slate-100 text-slate-900 text-[10px] rounded-xl px-2 outline-none font-black appearance-none cursor-pointer text-center focus:border-brand-primary transition-all">
                                                <option value="ZA">🇿🇦 +27</option>
                                                <option value="US">🇺🇸 +1</option>
                                            </select>
                                            <input type="tel" value={phone} onChange={(e) => setPhone(e.target.value)} className="col-span-2 w-full bg-white border-2 border-slate-100 text-slate-900 text-sm rounded-xl px-4 py-3.5 focus:border-brand-primary focus:bg-white outline-none transition-all font-bold shadow-inner" placeholder="Mobile Number" required />
                                        </div>
                                    </div>

                                    <button type="submit" className="w-full py-5 bg-slate-900 text-white font-black uppercase tracking-[0.15em] rounded-2xl text-[10px] shadow-lg hover:brightness-110 active:scale-[0.98] transition-all border-b-4 border-slate-700 mt-2">
                                        Verify Biometric Identity
                                    </button>

                                    <button 
                                        type="button" 
                                        onClick={onKioskMode} 
                                        className="w-full py-3.5 text-slate-400 font-bold uppercase tracking-widest text-[8px] hover:text-brand-primary transition-all mt-2"
                                    >
                                        New Hire? Start Here
                                    </button>

                                    <button 
                                        type="button" 
                                        onClick={() => onDemoBypass('manager')} 
                                        className="w-full py-3.5 text-slate-300 font-bold uppercase tracking-widest text-[8px] hover:text-brand-primary transition-all"
                                    >
                                        Continue as Manager
                                    </button>

                                    {isDev && (
                                        <div className="space-y-2 pt-4 border-t-2 border-red-200 mt-4">
                                            <p className="text-[8px] font-black text-red-400 uppercase tracking-widest text-center">Dev Mode</p>
                                            <button type="button" onClick={() => onDemoBypass('manager')} className="w-full py-3 bg-red-50 border-2 border-red-200 text-red-600 font-black uppercase tracking-widest text-[9px] rounded-xl hover:bg-red-100 transition-all">
                                                Bypass → Manager Dashboard
                                            </button>
                                            <button type="button" onClick={() => onDemoBypass('employee')} className="w-full py-3 bg-orange-50 border-2 border-orange-200 text-orange-600 font-black uppercase tracking-widest text-[9px] rounded-xl hover:bg-orange-100 transition-all">
                                                Bypass → New Hire Induction
                                            </button>
                                        </div>
                                    )}
                                </form>
                            </div>
                        )}

                        {step === 'verifying' && (
                            <div className="space-y-8 animate-fadeIn py-4">
                                <div className="text-center">
                                    <h3 className="text-lg font-black text-slate-900 uppercase italic tracking-tighter leading-none">Authorizing Session</h3>
                                    <p className="text-[8px] text-slate-400 mt-3 uppercase tracking-[0.3em]">Protocol v3.2</p>
                                </div>
                                <div className="space-y-4 relative max-w-[260px] mx-auto">
                                    <div className="absolute left-[15px] top-4 bottom-4 w-0.5 bg-slate-100 -z-10"></div>
                                    {verificationSteps.map((s, index) => {
                                        const isCompleted = index < verificationStepIndex;
                                        const isCurrent = index === verificationStepIndex;
                                        return (
                                            <div key={s.id} className={`flex items-center gap-4 transition-all duration-300 ${index > verificationStepIndex ? 'opacity-20' : 'opacity-100'}`}>
                                                <div className={`w-8 h-8 rounded-full flex items-center justify-center border-2 z-10 transition-all ${isCompleted ? 'bg-green-500 border-green-500 text-white' : isCurrent ? 'bg-white border-brand-primary text-brand-primary animate-pulse' : 'bg-slate-50 border-slate-200'}`}>
                                                    {isCompleted ? <CheckCircleIcon className="w-4 h-4" /> : <div className="scale-75">{s.icon}</div>}
                                                </div>
                                                <p className={`text-[9px] font-black uppercase tracking-tight ${isCompleted ? 'text-slate-800' : isCurrent ? 'text-brand-primary' : 'text-slate-400'}`}>{s.label}</p>
                                            </div>
                                        );
                                    })}
                                </div>
                            </div>
                        )}

                        {step === 'success' && (
                            <div className="flex flex-col items-center justify-center py-12 animate-fadeIn text-center space-y-6">
                                <div className="w-16 h-16 bg-green-500 rounded-full flex items-center justify-center shadow-[0_0_40px_rgba(34,197,94,0.3)] border-4 border-white">
                                    <CheckCircleIcon className="w-8 h-8 text-white" />
                                </div>
                                <div>
                                    <h2 className="text-xl font-black text-slate-900 dark:text-white uppercase italic leading-none">Access Granted</h2>
                                    <p className="text-slate-400 mt-3 text-[10px] uppercase font-bold tracking-widest animate-pulse">Syncing HR Registry...</p>
                                </div>
                            </div>
                        )}
                    </div>
                </main>

                <footer className="mt-8 mb-4 text-center">
                    <p className="text-[8px] font-black uppercase tracking-[0.5em] text-slate-300">twAIn Protocol • Node Paarl-HQ</p>
                </footer>
            </div>

            <style>{`
                .animate-spin-slow {
                    animation: spin 8s linear infinite;
                }
                @keyframes spin {
                    from { transform: rotate(0deg); }
                    to { transform: rotate(360deg); }
                }
            `}</style>
        </div>
    );
};

