const ActivityItem: React.FC<{ item: any; formatTime: (t: string) => string; onClick: () => void }> = ({ item, formatTime, onClick }) => {
    const stepLabel = STEP_DESCRIPTIONS[item.step - 1] || 'Processing Update';

    const statusBadge = useMemo(() => {
        const updatedAt = new Date(item.updatedAt).getTime();
        const now = new Date().getTime();
        const hoursStalled = (now - updatedAt) / 3600000;

        if (item.status === 'completed' || item.step >= 7) return { text: 'COMPLETED', color: 'text-emerald-600 bg-emerald-50 dark:bg-emerald-500/10 border-emerald-100 dark:border-emerald-500/20' };
        if (hoursStalled > 24) return { text: 'NEEDS ATTENTION', color: 'text-red-600 bg-red-50 dark:bg-red-500/10 border-red-100 dark:border-red-500/20' };
        if (item.step === 6) return { text: 'READY TO SIGN', color: 'text-blue-600 bg-blue-50 dark:bg-blue-500/10 border-blue-100 dark:border-blue-500/20' };
        if (item.step === 1) return { text: 'PENDING SIGNATURE', color: 'text-amber-600 bg-amber-50 dark:bg-amber-500/10 border-amber-100 dark:border-amber-500/20' };
        return { text: 'IN PROGRESS', color: 'text-[#0d9488] bg-teal-50 dark:bg-teal-500/10 border-teal-100 dark:border-teal-500/20' };
    }, [item.step, item.updatedAt, item.status]);

    return (
        <div 
            onClick={onClick}
            className="flex items-start gap-4 p-4 hover:bg-slate-50 dark:hover:bg-white/5 rounded-xl transition-all cursor-pointer group border-b border-slate-100 dark:border-white/5 last:border-0"
        >
            {item.profilePhoto ? (
                <img src={item.profilePhoto} alt="" className="w-10 h-10 rounded-full object-cover border-2 border-[#0d9488]/20 shadow-sm shrink-0" />
            ) : (
                <div className="shrink-0 w-10 h-10 rounded-full bg-gradient-to-br from-[#0d9488]/20 to-[#0d9488]/5 flex items-center justify-center text-[#0d9488] text-sm font-bold border border-[#0d9488]/20 shadow-inner">
                    {(item.name || '?').charAt(0)}
                </div>
            )}
            <div className="flex-1 min-w-0">
                <div className="flex justify-between items-center gap-2">
                    <p className="text-[11px] font-bold text-slate-800 dark:text-white uppercase truncate group-hover:text-[#0d9488] transition-colors">{item.name}</p>
                    <span className="text-[9px] font-mono text-slate-400 uppercase font-black">{formatTime(item.updatedAt)}</span>
                </div>
                <div className="flex items-center gap-2 mt-1.5 flex-wrap">
                    <p className="text-[10px] text-slate-500 dark:text-slate-400 font-medium leading-none truncate max-w-[120px]">{stepLabel}</p>
                    <div className="w-1 h-1 rounded-full bg-slate-300 dark:bg-slate-700"></div>
                    <span className={`px-2 py-0.5 rounded-full text-[7px] font-black uppercase tracking-widest border ${statusBadge.color}`}>
                        {statusBadge.text}
                    </span>
                </div>
            </div>
        </div>
    );
};

const StaffDashboard: React.FC = () => {
    const { setIsCopilotOpen, triggerHubRefresh, hubRefreshKey, homeActiveTab, setHomeActiveTab, setFocusedHireId, setCurrentHire, setCurrentHireId, openMedia, currentUser, persona } = useAppContext();
    const [pipeline, setPipeline] = useState<any[]>([]);
    const [loading, setLoading] = useState(true);
    const [overviewFilter, setOverviewFilter] = useState<'all' | 'stalled' | 'in-progress' | 'completed'>('all');

    const fetchData = async () => {
        setLoading(true);
        try {
            const resp = await fetch(
                `${SUPABASE_URL}/rest/v1/onboarding_telemetry?select=id,staff_name,status,step_reached,updated_at,created_at,metadata`,
                { headers: { 'apikey': SUPABASE_KEY, 'Authorization': `Bearer ${SUPABASE_KEY}` } }
            );
            const hires = await resp.json();
            setPipeline(hires || []);
        } catch (e) {
            console.error("Dashboard refresh failure", e);
        } finally {
            setLoading(false);
        }
    };

    useEffect(() => {
        fetchData();
    }, [hubRefreshKey]);

    const metrics = useMemo(() => {
        const now = new Date();
        const activeList = pipeline.filter(h => h.status?.toLowerCase() === 'in_progress' || !h.status || h.status?.toLowerCase() === 'pending');
        const active = activeList.length;
        const completedCount = pipeline.filter(h => h.status?.toLowerCase() === 'completed' || h.step_reached >= 7).length;

        const stalledList = pipeline.filter(h => {
            if (h.status?.toLowerCase() === 'completed' || h.step_reached >= 7) return false;
            const updated = new Date(h.updated_at || h.created_at);
            const diffHours = (now.getTime() - updated.getTime()) / (1000 * 60 * 60);
            return diffHours > 24;
        });
        const stalled = stalledList.length;

        const pendingCountersignCount = pipeline.filter(h => 
            h.metadata?.contract_status === 'signed' && !h.metadata?.countersigned_at
        ).length;

        // --- AVG. ONBOARD TIME CALCULATION ---
        const completedHires = pipeline.filter(h => 
            (h.status?.toUpperCase() === 'COMPLETED' || (h.metadata?.contract_status?.toLowerCase() === 'countersigned')) && 
            (h.metadata?.completed_at || h.updated_at) && 
            h.created_at
        );

        let avgOnboardTime = "—";
        let onboardTimeSublabel = "NO DATA";

        if (completedHires.length > 0) {
            const totalDays = completedHires.reduce((sum, h) => {
                const created = new Date(h.created_at).getTime();
                const finished = new Date(h.metadata?.completed_at || h.updated_at || h.created_at).getTime();
                return sum + (finished - created) / (1000 * 60 * 60 * 24);
            }, 0);

            const avg = totalDays / completedHires.length;
            avgOnboardTime = avg < 1 ? '< 1 DAY' : `${avg.toFixed(1)} DAYS`;
            onboardTimeSublabel = "AVG. CYCLE TIME";
        }

        return { active, stalled, stalledList, pendingCountersignCount, completedCount, avgOnboardTime, onboardTimeSublabel };
    }, [pipeline]);

    const filteredRecentActivity = useMemo(() => {
        const now = new Date();
        let list = pipeline.map(hire => ({
            name: hire.staff_name || 'Unknown',
            step: hire.step_reached || 1,
            status: hire.status?.toLowerCase(),
            updatedAt: hire.updated_at || hire.created_at,
            profilePhoto: hire.metadata?.profile_photo_url || null,
            id: hire.id,
            raw: hire
        }));

        if (overviewFilter === 'stalled') {
            list = list.filter(h => {
                if (h.status === 'completed' || h.step >= 7) return false;
                const diffHours = (now.getTime() - new Date(h.updatedAt).getTime()) / (1000 * 60 * 60);
                return diffHours > 24;
            });
        } else if (overviewFilter === 'in-progress') {
            list = list.filter(h => h.status !== 'completed' && h.step < 7);
        } else if (overviewFilter === 'completed') {
            list = list.filter(h => h.status === 'completed' || h.step >= 7);
        }

        return list.sort((a, b) => new Date(b.updatedAt).getTime() - new Date(a.updatedAt).getTime()).slice(0, 20);
    }, [pipeline, overviewFilter]);

    const getGreeting = () => {
        const hour = new Date().getHours();
        if (hour < 12) return 'Good morning';
        if (hour < 17) return 'Good afternoon';
        return 'Good evening';
    };

    // Fix: Updated managerName calculation to correctly access the persona name property from the USER_PERSONAS map.
    const managerName = currentUser?.name?.split(' ')[0] || (persona ? USER_PERSONAS[persona].name : 'Manager');

    const formatTimeAgo = (t: string) => {
        if (!t) return '';
        const s = Math.floor((new Date().getTime() - new Date(t).getTime()) / 1000);
        if (s < 60) return 'now';
        if (s < 3600) return `${Math.floor(s / 60)}m ago`;
        if (s < 86400) return `${Math.floor(s / 3600)}h ago`;
        return `${Math.floor(s / 86400)}d ago`;
    };

    const handleActivityClick = (hire: any) => {
        const contractStatus = hire.metadata?.contract_status?.toLowerCase();

        // If contract is signed and ready for manager countersign, open it directly
        if (contractStatus === 'signed' && hire.step_reached >= 6) {
            // Set this hire as the active context
            if (setCurrentHire) setCurrentHire(hire);
            if (setCurrentHireId) setCurrentHireId(hire.id);

            // Open the signed contract (or template) in MediaViewerModal for countersigning
            const contractUrl = hire.metadata?.signed_pdf_path || 
                'https://storage.googleapis.com/gemynd-public/projects/aiva/documents/Nashua%20Paarl%20Employment%20Contract%20Template_3.pdf';
            if (openMedia) openMedia(contractUrl);
        } else {
            // Default: navigate to pipeline view
            setFocusedHireId(hire.id);
            setHomeActiveTab('pipeline');
        }
    };

    return (
        <div className="p-6 md:p-10 bg-[#f8f9fb] dark:bg-transparent min-h-full transition-colors duration-300">
            <div className="max-w-7xl mx-auto space-y-4 pb-10">

                <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
                    <div>
                        <h1 className="text-2xl font-black text-slate-900 dark:text-white tracking-tight italic">{getGreeting()}, {managerName}</h1>
                        <div className="flex items-center gap-3 mt-1">
                             <p className="text-sm text-slate-500 dark:text-slate-400">Onboarding overview and hiring activity.</p>
                             <button 
                                onClick={() => { triggerHubRefresh(); fetchData(); }} 
                                className="p-1.5 hover:bg-slate-200 dark:hover:bg-white/10 rounded-lg transition-all text-slate-400"
                                title="Refresh"
                             >
                                <Loader2 className={`w-3.5 h-3.5 ${loading ? 'animate-spin' : ''}`} />
                             </button>
                        </div>
                    </div>
                </div>

                <div className="grid grid-cols-1 lg:grid-cols-12 gap-6 lg:gap-8 items-start">

                    <div className="lg:col-span-8 space-y-4 order-1 lg:order-2">

                        <div className="grid grid-cols-2 sm:grid-cols-4 gap-3 md:gap-4">
                            <QuickStat label="Active Hires" value={metrics.active} color="text-[#0d9488]" bgColor="bg-teal-50 dark:bg-teal-500/5" borderClass="border-teal-200 dark:border-teal-500/20" loading={loading} onClick={() => setHomeActiveTab('pipeline')} />
                            <QuickStat label="Attention Needed" value={metrics.stalled} color={metrics.stalled > 0 ? "text-amber-600" : "text-emerald-600"} bgColor={metrics.stalled > 0 ? "bg-amber-50 dark:bg-amber-500/5" : "bg-emerald-50 dark:bg-emerald-500/5"} borderClass={metrics.stalled > 0 ? "border-amber-200 dark:border-amber-500/20" : "border-emerald-200 dark:border-emerald-500/20"} loading={loading} onClick={() => { setOverviewFilter('stalled'); setHomeActiveTab('overview'); }} />
                            <QuickStat label="Fully Onboarded" value={metrics.completedCount} color="text-emerald-600" bgColor="bg-emerald-50 dark:bg-emerald-500/5" borderClass="border-emerald-200 dark:border-emerald-500/20" loading={loading} onClick={() => { setOverviewFilter('completed'); setHomeActiveTab('overview'); }} />
                            <QuickStat label={metrics.onboardTimeSublabel} value={metrics.avgOnboardTime} color="text-blue-600" bgColor="bg-blue-50 dark:bg-blue-500/5" borderClass="border-blue-200 dark:border-blue-500/20" loading={loading} />
                        </div>

                        <div className="flex items-center gap-1 bg-slate-100 dark:bg-slate-800/80 p-1.5 rounded-2xl w-fit shadow-sm border border-slate-200 dark:border-white/5 overflow-x-auto max-w-full">
                            <TabButton label="Overview" icon={LayoutDashboard} active={homeActiveTab === 'overview'} onClick={() => setHomeActiveTab('overview')} />
