                            <QuickStat label="Active Hires" value={metrics.active} color="text-[#0d9488]" bgColor="bg-teal-50 dark:bg-teal-500/5" borderClass="border-teal-200 dark:border-teal-500/20" loading={loading} onClick={() => setHomeActiveTab('pipeline')} />
                            <QuickStat label="Attention Needed" value={metrics.stalled} color={metrics.stalled > 0 ? "text-amber-600" : "text-emerald-600"} bgColor={metrics.stalled > 0 ? "bg-amber-50 dark:bg-amber-500/5" : "bg-emerald-50 dark:bg-emerald-500/5"} borderClass={metrics.stalled > 0 ? "border-amber-200 dark:border-amber-500/20" : "border-emerald-200 dark:border-emerald-500/20"} loading={loading} onClick={() => { setOverviewFilter('stalled'); setHomeActiveTab('overview'); }} />
                            <QuickStat label="Fully Onboarded" value={metrics.completedCount} color="text-emerald-600" bgColor="bg-emerald-50 dark:bg-emerald-500/5" borderClass="border-emerald-200 dark:border-emerald-500/20" loading={loading} onClick={() => { setOverviewFilter('completed'); setHomeActiveTab('overview'); }} />
                            <QuickStat label={metrics.onboardTimeSublabel} value={metrics.avgOnboardTime} color="text-blue-600" bgColor="bg-blue-50 dark:bg-blue-500/5" borderClass="border-blue-200 dark:border-blue-500/20" loading={loading} />
                        </div>

                        <div className="flex items-center gap-1 bg-slate-100 dark:bg-slate-800/80 p-1.5 rounded-2xl w-fit shadow-sm border border-slate-200 dark:border-white/5 overflow-x-auto max-w-full">
