                                </p>

                                {/* Proactive nudge — shows when there's actionable data */}
                                {metrics.stalledList?.length > 0 ? (
                                    <div className="mt-3 px-3 py-2.5 bg-white/10 rounded-xl animate-fadeIn">
                                        <p className="text-[10px] text-white/80 leading-relaxed">
