export const MediaViewerModal: React.FC = () => {
    const { 
        activeMediaUrl, 
        closeMedia, 
        addToast, 
        triggerSuccessFeedback, 
        currentHire, 
        currentHireId, 
        persona,
        triggerHubRefresh
    } = useAppContext();

    const [isLoaded, setIsLoaded] = useState(false);
