const ProfilePhotoCapture: React.FC<{
    onComplete: (url: string | null) => void;
    hireName: string;
    hireId: string;
    currentMetadata: any;
}> = ({ onComplete, hireName, hireId, currentMetadata }) => {
    const videoRef = useRef<HTMLVideoElement>(null);
    const streamRef = useRef<MediaStream | null>(null);
    const [captureState, setCaptureState] = useState<'preview' | 'review' | 'uploading'>('preview');
    const [capturedBlob, setCapturedBlob] = useState<Blob | null>(null);
    const [capturedUrl, setCapturedUrl] = useState<string | null>(null);
    const [error, setError] = useState<string | null>(null);

    useEffect(() => {
        startCamera();
        return () => {
            if (streamRef.current) {
                streamRef.current.getTracks().forEach(t => t.stop());
            }
        };
    }, []);

    const startCamera = async () => {
        try {
            setError(null);
            const stream = await navigator.mediaDevices.getUserMedia({ 
                video: { facingMode: 'user', width: 640, height: 640 } 
            });
            streamRef.current = stream;
            if (videoRef.current) {
                videoRef.current.srcObject = stream;
            }
        } catch (err) {
            console.error('Camera access denied:', err);
            setError("We need camera access for your staff photo. You can skip this and add it later.");
        }
    };

    const capturePhoto = () => {
        const canvas = document.createElement('canvas');
        canvas.width = 400;
        canvas.height = 400;
        const ctx = canvas.getContext('2d');
        if (!ctx || !videoRef.current) return;

        const video = videoRef.current;
        const size = Math.min(video.videoWidth, video.videoHeight);
        const sx = (video.videoWidth - size) / 2;
        const sy = (video.videoHeight - size) / 2;

        // Mirror horizontally for selfie
        ctx.translate(400, 0);
        ctx.scale(-1, 1);
        ctx.drawImage(video, sx, sy, size, size, 0, 0, 400, 400);

        canvas.toBlob(blob => {
            if (blob) {
                setCapturedBlob(blob);
                setCapturedUrl(URL.createObjectURL(blob));
                setCaptureState('review');
            }
        }, 'image/jpeg', 0.85);
    };

    const uploadPhoto = async () => {
        if (!capturedBlob || !hireId) return;
        setCaptureState('uploading');
        try {
            const fileName = `profile_${hireId}_${Date.now()}.jpg`;
            const filePath = `profiles/${fileName}`;
            const bucketName = 'project-aiva-afridroids';

            // Upload directly to Supabase Storage
            const uploadResp = await fetch(
                `${SUPABASE_URL}/storage/v1/object/${bucketName}/${filePath}`,
                {
                    method: 'POST',
                    headers: {
                        'apikey': SUPABASE_KEY,
                        'Authorization': `Bearer ${SUPABASE_KEY}`,
                        'Content-Type': 'image/jpeg',
                        'x-upsert': 'true'
                    },
                    body: capturedBlob
                }
            );

            if (!uploadResp.ok) {
                throw new Error(`Storage upload failed: ${uploadResp.status}`);
            }

            // Get the public URL
            const publicUrl = `${SUPABASE_URL}/storage/v1/object/public/${bucketName}/${filePath}`;

            // Save record to uploaded_files table
            await fetch(
                `${SUPABASE_URL}/rest/v1/uploaded_files`,
                {
                    method: 'POST',
                    headers: {
                        'apikey': SUPABASE_KEY,
                        'Authorization': `Bearer ${SUPABASE_KEY}`,
                        'Content-Type': 'application/json',
                        'Prefer': 'return=minimal'
                    },
                    body: JSON.stringify({
                        file_name: fileName,
                        file_path: filePath,
                        file_type: 'image/jpeg',
                        file_size: capturedBlob.size,
                        public_url: publicUrl,
                        hire_id: hireId,
                        document_type: 'profile',
                        document_status: 'uploaded',
                        app_id: 'aiva',
                        org_id: '71077b47-66e8-4fd9-90e7-709773ea6582',
                        uploaded_by: 'aiva-kiosk',
                        metadata: { type: 'profile_photo' }
                    })
                }
            );

            // Update onboarding_telemetry metadata with photo URL
            const getResp = await fetch(
                `${SUPABASE_URL}/rest/v1/onboarding_telemetry?id=eq.${hireId}&select=metadata`,
                { headers: { 'apikey': SUPABASE_KEY, 'Authorization': `Bearer ${SUPABASE_KEY}` } }
            );
            const currentData = await getResp.json();
            const currentMeta = currentData?.[0]?.metadata || {};

            await fetch(
                `${SUPABASE_URL}/rest/v1/onboarding_telemetry?id=eq.${hireId}`,
                {
                    method: 'PATCH',
                    headers: {
                        'apikey': SUPABASE_KEY,
                        'Authorization': `Bearer ${SUPABASE_KEY}`,
                        'Content-Type': 'application/json',
                        'Prefer': 'return=minimal'
                    },
                    body: JSON.stringify({
                        metadata: {
                            ...currentMeta,
                            profile_photo_url: publicUrl
                        }
                    })
                }
            );

            onComplete(publicUrl);
        } catch (e) {
            console.error('Upload photo error:', e);
            onComplete(null);
        }
    };

    const handleRetake = () => {
        setCapturedBlob(null);
        setCapturedUrl(null);
        setCaptureState('preview');
        startCamera();
    };

    return (
        <div className="fixed inset-0 z-[250] bg-slate-900/90 backdrop-blur-xl flex items-center justify-center p-4 animate-fadeIn">
            <div className="bg-white dark:bg-slate-800 w-full max-md rounded-[3rem] shadow-2xl p-8 flex flex-col items-center border border-white/10">
                <div className="text-center space-y-2 mb-8">
                    <h3 className="text-2xl font-black text-slate-800 dark:text-white uppercase italic tracking-tighter">Welcome to the team, {hireName.split(' ')[0]}! 🎉</h3>
                    <p className="text-sm text-slate-500 font-medium leading-relaxed">Let's capture a photo for your staff profile.</p>
                </div>

                <div className="relative w-64 h-64 rounded-full overflow-hidden border-4 border-[#0d9488]/30 shadow-2xl bg-slate-100 dark:bg-slate-950 mb-8 flex items-center justify-center">
                    {error ? (
                        <div className="p-6 text-center">
                            <AlertCircle className="w-8 h-8 text-amber-500 mx-auto mb-2" />
                            <p className="text-xs text-slate-500 font-bold">{error}</p>
                        </div>
                    ) : captureState === 'preview' ? (
                        <video 
                            ref={videoRef} 
                            autoPlay 
                            playsInline 
                            muted 
                            className="w-full h-full object-cover" 
                            style={{ transform: 'scaleX(-1)' }} 
                        />
                    ) : (
                        <img src={capturedUrl || ''} alt="Captured" className="w-full h-full object-cover" />
                    )}

                    {captureState === 'uploading' && (
                        <div className="absolute inset-0 bg-black/40 flex items-center justify-center">
                            <Loader2 className="w-10 h-10 text-white animate-spin" />
                        </div>
                    )}
                </div>

                {!error && (
                    <div className="w-full space-y-4">
                        {captureState === 'preview' ? (
                            <button 
                                onClick={capturePhoto}
                                className="w-full py-4 bg-[#0d9488] text-white font-black rounded-2xl shadow-xl hover:brightness-110 active:scale-[0.98] transition-all uppercase tracking-widest text-xs"
                            >
                                Capture Photo
                            </button>
                        ) : captureState === 'review' ? (
                            <div className="grid grid-cols-2 gap-3">
                                <button 
                                    onClick={handleRetake}
                                    className="py-4 bg-slate-100 dark:bg-slate-700 text-slate-600 dark:text-slate-300 font-black rounded-2xl uppercase tracking-widest text-[10px]"
                                >
                                    Retake
                                </button>
                                <button 
                                    onClick={uploadPhoto}
                                    className="py-4 bg-[#0d9488] text-white font-black rounded-2xl shadow-xl hover:brightness-110 active:scale-[0.98] transition-all uppercase tracking-widest text-[10px]"
                                >
                                    Use This Photo
                                </button>
                            </div>
                        ) : null}
                    </div>
                )}

                <button 
                    onClick={() => onComplete(null)}
                    disabled={captureState === 'uploading'}
                    className="mt-6 text-sm text-slate-400 hover:text-slate-600 underline font-bold transition-colors"
                >
                    Skip for now →
                </button>
            </div>
        </div>
    );
};

